import React, { useState, useEffect } from 'react';
import api from '../../services/api';

const OrcamentoForm = () => {
  const [nomeOrcamento, setNomeOrcamento] = useState('');
  const [clienteSelecionado, setClienteSelecionado] = useState(null);
  const [termoBusca, setTermoBusca] = useState('');
  const [sugestoes, setSugestoes] = useState([]);
  const [observacoes, setObservacoes] = useState('');
  const [itens, setItens] = useState([{ descricao: '', valor: '' }]);

  useEffect(() => {
    if (termoBusca.length > 2) {
      api.get(`/clientes/search?nome=${termoBusca}`).then(response => {
        setSugestoes(response.data);
      });
    } else {
      setSugestoes([]);
    }
  }, [termoBusca]);

  const handleItemChange = (index, event) => {
    const values = [...itens];
    values[index][event.target.name] = event.target.value;
    setItens(values);
  };

  const handleAddItem = () => {
    setItens([...itens, { descricao: '', valor: '' }]);
  };

  const handleRemoveItem = index => {
    const values = [...itens];
    values.splice(index, 1);
    setItens(values);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    const orcamento = {
      nome_orcamento: nomeOrcamento,
      id_cliente: clienteSelecionado ? clienteSelecionado.id_cliente : null,
      observacoes,
      itens
    };
    try {
      await api.post('/orcamentos', orcamento);
      alert('Orçamento criado com sucesso!');
    } catch (error) {
      alert('Erro ao criar orçamento.');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h2>Criar Orçamento</h2>
      <div>
        <label>Nome do Orçamento:</label>
        <input
          type="text"
          value={nomeOrcamento}
          onChange={e => setNomeOrcamento(e.target.value)}
        />
      </div>
      <div>
        <label>Vincular orçamento ao cliente (opcional):</label>
        <input
          type="text"
          value={termoBusca}
          onChange={e => setTermoBusca(e.target.value)}
          placeholder="Digite o nome do cliente"
        />
        {sugestoes.length > 0 && (
          <ul>
            {sugestoes.map(cliente => (
              <li
                key={cliente.id_cliente}
                onClick={() => {
                  setClienteSelecionado(cliente);
                  setTermoBusca(cliente.nome);
                  setSugestoes([]);
                }}
              >
                {cliente.nome}
              </li>
            ))}
          </ul>
        )}
      </div>

      <h3>Itens do Orçamento</h3>
      {itens.map((item, index) => (
        <div key={index}>
          <input
            type="text"
            name="descricao"
            placeholder="Insira um produto/serviço"
            value={item.descricao}
            onChange={e => handleItemChange(index, e)}
          />
          <input
            type="text"
            name="valor"
            placeholder="Valor"
            value={item.valor}
            onChange={e => handleItemChange(index, e)}
          />
          <button type="button" onClick={() => handleRemoveItem(index)}>Remover</button>
        </div>
      ))}
      <button type="button" onClick={handleAddItem}>Adicionar Item</button>

      <div>
        <label>Observações:</label>
        <textarea
          value={observacoes}
          onChange={e => setObservacoes(e.target.value)}
        />
      </div>

      <button type="submit">Salvar Orçamento</button>
    </form>
  );
};

export default OrcamentoForm;
